mapper.select:
SELECT r.id AS registerId, TO_CHAR(r.visit_date, 'YYYY-MM-DD') AS visitDate, d.dept_name AS deptName, e.realname AS doctorName, mr.diagnosis AS diagnosis, r.visit_state AS visitState, CASE r.visit_state WHEN 'REGISTERED' THEN '待就诊' WHEN 'CONSULTING' THEN '就诊中' WHEN 'FINISHED' THEN '已完成' WHEN 'CANCELLED' THEN '已取消' ELSE '' END AS visitStateName, r.noon AS noon, r.queue_no AS queueNumber, r.checkin_status AS checkinStatus, rl.regist_fee AS registFee, r.deptment_id AS deptId, r.employee_id AS doctorId, p.real_name AS patientName, p.gender AS gender, EXTRACT(YEAR FROM AGE(CURRENT_DATE, p.birthdate))::INTEGER AS age, mr.allergy AS allergyHistory, p.case_number AS caseNumber FROM register r LEFT JOIN department d ON r.deptment_id = d.id LEFT JOIN employee e ON r.employee_id = e.id LEFT JOIN medical_record mr ON r.id = mr.register_id LEFT JOIN regist_level rl ON r.regist_level_id = rl.id LEFT JOIN patient p ON r.patient_id = p.id WHERE r.patient_id = #{patientId}
AND r.visit_state = #{visitState}
ORDER BY r.visit_date DESC LIMIT #{limit} OFFSET #{offset}

SELECT COUNT(*)
FROM register
WHERE patient_id = #{patientId}

    AND visit_state = #{visitState}

SELECT r.id AS registerId, 'REGISTER' AS itemType, '挂号费' AS itemName, r.id AS itemId, r.regist_money AS amount, CASE WHEN r.visit_state = 'CANCELLED' THEN 'CANCELLED' WHEN r.regist_money IS NOT NULL AND r.regist_money > 0 THEN 'UNPAID' ELSE 'PAID' END AS orderState, d.dept_name AS deptName, r.visit_date AS visitDate, r.create_time AS createTime, NULL AS payTime FROM register r LEFT JOIN department d ON r.deptment_id = d.id WHERE r.patient_id = #{patientId} AND r.regist_money IS NOT NULL AND r.regist_money > 0 AND r.visit_state != 'CANCELLED'
AND r.regist_money > 0
ORDER BY r.create_time DESC LIMIT #{limit} OFFSET #{offset}
